import { glob } from 'glob'
import { defineConfig } from 'tsup'

function getEntryPoints() {
  // Get all JS files except test files
  return glob.sync('src/**/*.js', {
    ignore: ['**/*.test.js', '**/*.spec.js'],
  })
}

export default defineConfig([
  // ESM build
  {
    entry: getEntryPoints(),
    format: ['esm'],
    outDir: 'dist/esm',
    clean: true,
    bundle: false,
    splitting: false,
    sourcemap: false,
    dts: false,
  },
  // CJS build
  {
    entry: getEntryPoints(),
    format: ['cjs'],
    outDir: 'dist/cjs',
    outExtension: () => ({ js: '.cjs' }),
    clean: false,
    bundle: false,
    splitting: false,
    sourcemap: false,
    dts: false,
  },
  // Types build
  {
    entry: getEntryPoints(),
    dts: {
      only: true,
    },
    outDir: 'dist/types',
    outExtension: () => ({ dts: '.d.cts' }),
    clean: false,
  },
])
